+        }
+
+        if label.len() > 50 {
+            return Err(ValidationError::new("label", "exceeds 50 characters"));
+        }
+
+        if !label
+            .chars()
+            .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
+        {
+            return Err(ValidationError::new(
+                "label",
+                "invalid characters (only alphanumeric, hyphen, underscore allowed)",
+            ));
+        }
+
+        Ok(())
+    }
+}
